#include<bits/stdc++.h>
using namespace std;

int n;
long long a[55];
char dfs(int x,int y)
{
	if(y==0) return "moo"[x-1];
	if(x>a[y-1]+1&&x<a[y-1]+4+y) return 'o';
	if(x==a[y-1]+1) return 'm';
	if(x<=a[y-1]) return dfs(x,y-1);
	return dfs(x-a[y-1]-3-y,y-1); 
}
int main()
{
	cin>>n;
	long long i,j;
	for(j=0,i=3;n>i;j++,i=i*2+j+3) a[j]=i;
	cout<<dfs(n,j);
	return 0;
}
